import{_ as t,o as a,c as r,ag as s}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"Contrats","description":"","frontmatter":{},"headers":[],"relativePath":"fr/features/contracts.md","filePath":"fr/features/contracts.md"}'),n={name:"fr/features/contracts.md"};function i(o,e,l,c,u,d){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="contrats" tabindex="-1">Contrats <a class="header-anchor" href="#contrats" aria-label="Permalink to &quot;Contrats&quot;">​</a></h1><p>Gerez les accords de services recurrents et les contrats de location avec des calendriers de facturation automatiques.</p><h2 id="vue-d-ensemble" tabindex="-1">Vue d&#39;ensemble <a class="header-anchor" href="#vue-d-ensemble" aria-label="Permalink to &quot;Vue d&#39;ensemble&quot;">​</a></h2><p>Les contrats representent des accords en cours avec des clients -- tels que des contrats de services mensuels, des baux de location ou des plans de maintenance. Ils peuvent generer automatiquement des factures selon un calendrier defini.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Le module contrats est optionnel. Activez-le dans <strong>Entreprise &gt; Fonctionnalites</strong> si vous ne le voyez pas dans la navigation.</p></div><h2 id="creer-un-contrat" tabindex="-1">Creer un contrat <a class="header-anchor" href="#creer-un-contrat" aria-label="Permalink to &quot;Creer un contrat&quot;">​</a></h2><ol><li>Allez dans <strong>Contrats &gt; Nouveau contrat</strong></li><li>Remplissez : <ul><li><strong>Nom</strong> -- Un titre descriptif (par ex., &quot;Service de nettoyage mensuel&quot;)</li><li><strong>Client</strong> -- Le client partie au contrat</li><li><strong>Montant</strong> -- Le montant de facturation recurrent</li><li><strong>Recurrence</strong> -- Frequence de facturation (hebdomadaire, mensuelle, trimestrielle, annuelle)</li><li><strong>Date de debut</strong> -- Quand le contrat commence</li><li><strong>Date de fin</strong> -- Date de fin optionnelle</li><li><strong>Description</strong> -- Conditions et details</li></ul></li><li>Cliquez sur <strong>Enregistrer</strong></li></ol><h2 id="statuts-des-contrats" tabindex="-1">Statuts des contrats <a class="header-anchor" href="#statuts-des-contrats" aria-label="Permalink to &quot;Statuts des contrats&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Statut</th><th>Description</th></tr></thead><tbody><tr><td><strong>Actif</strong></td><td>Actuellement en vigueur, genere des factures</td></tr><tr><td><strong>Inactif</strong></td><td>En pause -- aucune facture generee</td></tr></tbody></table><h2 id="facturation-automatique" tabindex="-1">Facturation automatique <a class="header-anchor" href="#facturation-automatique" aria-label="Permalink to &quot;Facturation automatique&quot;">​</a></h2><p>Les contrats actifs avec un calendrier de recurrence generent automatiquement des factures a chaque periode de facturation. Le systeme :</p><ol><li>Cree un brouillon de facture base sur les termes du contrat</li><li>Applique le client, le montant et la description corrects</li><li>Suit vos parametres de numerotation des factures</li></ol><p>Vous pouvez examiner et envoyer les factures generees manuellement, ou configurer l&#39;envoi automatique.</p><h2 id="liaison-aux-actifs" tabindex="-1">Liaison aux actifs <a class="header-anchor" href="#liaison-aux-actifs" aria-label="Permalink to &quot;Liaison aux actifs&quot;">​</a></h2><p>Les contrats peuvent etre lies aux <a href="/fr/features/objects">objets/actifs</a> pour la gestion locative :</p><ul><li>Associez un contrat a une propriete, un vehicule ou un equipement</li><li>Suivez quels actifs sont actuellement loues et a qui</li><li>Consultez l&#39;historique des contrats par actif</li></ul><h2 id="indicateurs" tabindex="-1">Indicateurs <a class="header-anchor" href="#indicateurs" aria-label="Permalink to &quot;Indicateurs&quot;">​</a></h2><p>La page de liste des contrats affiche des indicateurs de synthese :</p><ul><li>Total des contrats actifs</li><li>Valeur totale des contrats</li><li>Contrats par type de recurrence</li></ul><h2 id="actions-groupees" tabindex="-1">Actions groupees <a class="header-anchor" href="#actions-groupees" aria-label="Permalink to &quot;Actions groupees&quot;">​</a></h2><ul><li><strong>Changer le statut</strong> -- Activez ou desactivez plusieurs contrats</li><li><strong>Archiver</strong> -- Deplacez vers les archives</li><li><strong>Restaurer</strong> -- Recuperez les contrats archives</li></ul><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Utilisez les contrats conjointement avec les <a href="/fr/features/recurring-invoices">factures recurrentes</a> pour differents scenarios de facturation</li><li>Liez les contrats aux objets pour une gestion locative complete</li><li>Definissez des dates de fin pour etre averti avant l&#39;expiration des contrats</li><li>Utilisez le filtre des contrats pour voir les actifs vs. les inactifs en un coup d&#39;oeil</li></ul>',23)])])}const h=t(n,[["render",i]]);export{p as __pageData,h as default};
